--- 挂机头顶飘字
local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LFightIdleHud:LxNodeBase
local LFightIdleHud = LxClass("LFightIdleHud", LxNodeBase)
-----------------------------------------------------------------
local CS = CS
local typeofCanvasGroup = typeof(UnityEngine.CanvasGroup)
local typeofBtHudFollow = typeof(CardEHT.BtHudFollow)

-----------------------------------------------------------------
function LFightIdleHud:LFightIdleHud()
	--挂载父节点
	self._parentTrans = nil
	--飘字对象
	---@type LFightIdleObject
	self._obj = nil
	--hud数据
	self._hudDataList = nil

	self._btNodeTrans = nil

	--- {hudType=1,trans=trans,tween=tween}
	self._hudShowList = nil

	--上次obj 位置在界面上的世界坐标
	self._lastWorldPos = nil

	self._curIndex = 0

	self._maxIndex = 0

	self._nextDelay = nil

	self._playendCount = 0

	self._isLast = false

	self._isDestroyed = false
end

-----------------------------------------------------------------
function LFightIdleHud:ShowBtNode()
	local btHudFollow = self._btNodeTrans:GetComponent(typeofBtHudFollow)
	if btHudFollow then
		local followPos
		local obj = self._obj
		if obj and not obj:IsDestroy() then
			followPos = obj:GetTopNodePos()
		end
		local sceneCamera = gLGameScene:GetCurrentSceneCamera()
		local uiSceneCamrea = LGameUI.GetUICamera()
		btHudFollow:Init(uiSceneCamrea, sceneCamera)
		btHudFollow:DoFollowPos(followPos or Vector3(0, 0, 0))
	end
	self._btHudFollowCom = btHudFollow
	CS.ShowObject(self._btNodeTrans, true)
end

---开始下一个hud的表现
function LFightIdleHud:ShowNextHud()
	local oldIndex = self._curIndex
	if oldIndex >= self._maxIndex then
		self._isLast = true
		return
	end

	local idx = oldIndex + 1
	self._curIndex = idx

	if idx == 1 then
		self:ShowBtNode()
	end

	self._isLast = idx >= self._maxIndex
	local nextData = self._hudDataList[idx + 1]
	self._nextDelay = nextData and nextData:GetDelay() or 0

	local hudShowData = self._hudShowList[idx]
	local oldShowData = self._hudShowList[oldIndex]
	local hudData = hudShowData.data

	CS.ShowObject(hudShowData.trans, true)

	local trans = hudShowData.trans
	local pos = self:GetObjPos()
	if pos then
		self._lastWorldPos = pos
	end

	if self._lastWorldPos then trans.position = self._lastWorldPos end
	--第二个，需要用前一个的当前坐标Y + 偏移

	--初始化状态
	local canvasGroup = trans:GetComponent(typeofCanvasGroup)
	canvasGroup.alpha = 1

	local stayTime = 0.0 -- 停留时间
	local moveY = 8
	local moveTime = 0.8
	local alphaTime = 0.15 -- alpha 消失时间

	local index = hudData:GetIndex()
	if idx > 1 then
		local pos = oldShowData.trans.localPosition
		local nowPos = trans.localPosition
		nowPos.y = pos.y + hudData:GetFloatHurtY()
		local minX, maxX = hudData:GetFloatHurtX()
		if minX ~= 0 and maxX ~= 0 then
			local randX = math.random() * (maxX - minX) + minX
			nowPos.x = pos.x + randX
		end
		trans.localPosition = nowPos
	elseif index > 0 then
		local nowPos = trans.localPosition
		nowPos.y = index * moveY + hudData:GetFloatHurtY()
		local minX, maxX = hudData:GetFloatHurtX()
		if minX ~= 0 and maxX ~= 0 then
			local randX = math.random() * (maxX - minX) + minX
			nowPos.x = nowPos.x + randX
		end
		trans.localPosition = nowPos
	end


	local alphaStartPos = stayTime + moveTime - alphaTime

	local seqtween = YXTween.TweenSequenceIns()
	seqtween:AppendInterval(stayTime)

	--alpha 动画消失
	local alphaTween = canvasGroup:DOFade(0, alphaTime):SetEase(DG.Tweening.Ease.InSine)

	-- Y移动动画
	local moveTween = trans:DOLocalMoveY(trans.localPosition.y + moveY, moveTime)

	seqtween:Append(moveTween)
	seqtween:Insert(alphaStartPos, alphaTween)

	seqtween:OnComplete(function()
		self._playendCount = self._playendCount + 1
		self._hudShowList[idx].tween = nil
	end)

	hudShowData.tween = seqtween

	seqtween:PlayForward()
end

-----------------------------------------------------------------
function LFightIdleHud:InitHud(parentTrans, obj, hudDataList, hudCtrl)
	self._hudCtrl = hudCtrl
	self._parentTrans = parentTrans
	self._obj = obj
	self._hudDataList = hudDataList

	self._lastWorldPos = self:GetObjPos()

	self._startTime = hudCtrl:GetTime()

	self:PrepareAllHud()
	self:ShowNextHud()
end

--初始化所有的伤害
function LFightIdleHud:PrepareAllHud()
	local hudCtrl = self:GetHudCtrl()
	local btNode = hudCtrl:MakeHudTransFromCache(LFightIdleConst.HUD_BTNODE)
	self._btNodeTrans = btNode
	CS.SetParentTrans(btNode, self._parentTrans)
	CS.ShowObject(btNode, false)

	local hudDataList = self._hudDataList
	local hudShowList = {}
	self._hudShowList = hudShowList
	local hudShowData = nil
	for k, v in ipairs(hudDataList) do
		hudShowData = self:CreateHud(v)
		table.insert(hudShowList, hudShowData)
	end

	self._maxIndex = #hudShowList
end

--伤害类型转成hud的类型
function LFightIdleHud:ConvertHudType(changeType)
	if changeType == LFightIdleConst.HP_TYPE_MISS then
		return LFightIdleConst.HUD_WORLD, ccClientText(10917)
	elseif changeType == LFightIdleConst.HP_TYPE_HEAL then
		return LFightIdleConst.HUD_HEAL
	elseif changeType == LFightIdleConst.HP_TYPE_CRIT then
		return LFightIdleConst.HUD_CRIT
	elseif changeType == LFightIdleConst.HP_TYPE_HURT_HERO then
		return LFightIdleConst.HUD_HURT_HERO
	else
		return LFightIdleConst.HUD_HURT
	end
end

function LFightIdleHud:CreateHud(hudData)
	local hudType, word = self:ConvertHudType(hudData:GetChangeType())

	local hudCtrl = self:GetHudCtrl()
	local hudTrans = hudCtrl:MakeHudTransFromCache(hudType)
	CS.SetParentTrans(hudTrans, self._btNodeTrans)
	hudTrans.localScale = hudData:GetScale()

	local text = ""
	if hudType == LFightIdleConst.HUD_WORLD then
		text = word
	else
		--local bAddNegative = hudType == LFightIdleConst.HUD_HURT

		local addCritStr = (hudType == LFightIdleConst.HUD_CRIT) and "<sprite index=13>" or ""
		text = addCritStr .. LUtil.FormatHurtNumSpriteText(math.abs(hudData:GetHurt()), false, 120)
	end

	local textTrans = CS.FindTrans(hudTrans, "Text")
	self:SetXTextContent(textTrans, text)

	CS.ShowObject(hudTrans, false)

	return { hudType = hudType, trans = hudTrans, data = hudData, tween = nil }
end

--获取对象当前坐标在ui坐标中的映射位置
function LFightIdleHud:GetObjPos()
	local obj = self._obj
	if obj and not obj:IsDestroy() then
		local objPos = obj:GetTopNodePos()
		if not objPos then return Vector3.zero end
		local sceneCamera   = gLGameScene:GetCurrentSceneCamera()
		local uiSceneCamrea = LGameUI.GetUICamera()
		objPos              = Vector3(objPos.x, objPos.y, 0)
		--坐标轴转换：将角色位置坐标，转化为屏幕坐标。屏幕坐标转化为世界坐标，设置UI坐标。
		local screenPos     = sceneCamera:WorldToScreenPoint(objPos) --Vector3
		local worldPos      = uiSceneCamrea:ScreenToWorldPoint(screenPos)
		worldPos.z          = 0
		return worldPos
	end
end

-----------------------------------------------------------------
function LFightIdleHud:OnRun(time)
	if self:IsDestroy() then return false end
	if self._playendCount >= self._maxIndex then return false end
	if not self._isLast then
		time = time - self._startTime
		if self._nextDelay <= time then
			self:ShowNextHud()
		end
	end
	return true
end

-----------------------------------------------------------------
function LFightIdleHud:Destroy()
	if self._hudShowList then
		local hudCtrl = self:GetHudCtrl()
		for k, v in ipairs(self._hudShowList) do
			if v.tween then v.tween:Kill(false) end
			v.tween = nil
			if v.trans then
				hudCtrl:ReturnHudTransToCache(v.hudType, v.trans)
			end
			v.trans = nil
		end
		self._hudShowList = nil
	end

	if self._btNodeTrans then
		local hudCtrl = self:GetHudCtrl()
		hudCtrl:ReturnHudTransToCache(LFightIdleConst.HUD_BTNODE, self._btNodeTrans)
		if self._btHudFollowCom then
			self._btHudFollowCom:ClearFollow()
		end
		self._btNodeTrans = nil
	end

	table.removeall(self)

	self._isDestroyed = true
end

function LFightIdleHud:IsDestroy()
	return self._isDestroyed
end

function LFightIdleHud:GetHudCtrl()
	return self._hudCtrl
end

return LFightIdleHud
